import{_ as a,o as t,c as s,a3 as i}from"./chunks/framework.B4Nz3hZ_.js";const m=JSON.parse(`{"title":"FAQ","description":"","frontmatter":{"head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"FAQPage\\",\\"mainEntity\\":[{\\"@type\\":\\"Question\\",\\"name\\":\\"What shells are supported?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"amoxide supports Fish (fully), PowerShell 5.1+7, Zsh, Bash 3.2+, and Brush (bash-compatible). Nushell support is planned.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How is amoxide different from shell aliases in dotfiles?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Traditional aliases are static and defined once in .bashrc or .zshrc. amoxide adds: Profiles (named groups you can activate/deactivate), Project aliases (auto-loaded per directory like direnv), Parameterized aliases (template syntax for composable commands), and multiple active profiles with layered precedence.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Where are my aliases stored?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Global aliases are stored in ~/.config/amoxide/config.toml. Profile aliases are stored in ~/.config/amoxide/profiles.toml. Project aliases are stored in a .aliases file in the project directory.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use amoxide alongside my existing shell aliases?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. amoxide aliases coexist with your shell's native aliases. If there is a name conflict, amoxide's alias takes precedence while it is active.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What is am-tui?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"am-tui is a separate binary (amoxide-tui) that provides an interactive terminal UI for managing aliases visually. Run it with: am tui. Install via: brew install sassman/tap/amoxide-tui\\"}}]}"]]},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}`),l={name:"faq.md"};function o(r,e,n,d,h,c){return t(),s("div",null,[...e[0]||(e[0]=[i("",17)])])}const u=a(l,[["render",o]]);export{m as __pageData,u as default};
